import{_ as o,o as a,c as r,a3 as t}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"43. Working Away From Home","description":"","frontmatter":{"title":"43. Working Away From Home","eba":"Allied Health Professionals 2021-2026","topics":["leave","public-holidays","allowances","travel"]},"headers":[],"relativePath":"ebas/allied-health/allowances/43-working-away-from-home.md","filePath":"ebas/allied-health/allowances/43-working-away-from-home.md"}'),n={name:"ebas/allied-health/allowances/43-working-away-from-home.md"};function l(i,e,s,h,p,m){return a(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="_43-working-away-from-home" tabindex="-1">43. Working Away From Home <a class="header-anchor" href="#_43-working-away-from-home" aria-label="Permalink to &quot;43. Working Away From Home&quot;">​</a></h1><p><strong>43.1</strong> For each night an Employee is required by the Employer to be absent overnight from their usual place of residence, for example where an Employee cannot reasonably travel from or back to their usual place of residence on the day on which they are required to work by the Employer, the Employer will:</p><p><strong>(a)</strong> pay the Employee the higher of the following:</p><p><strong>(i)</strong> 2.5% of the AHP1 Grade 1, Year 1 rate per overnight period between Monday and Friday; or</p><p><strong>(ii)</strong> 5% of the AHP1 Grade 1, Year 1 rate per overnight period that includes a Saturday, Sunday or Public Holiday; and</p><p><strong>(b)</strong> pay for all reasonably incurred expenses in respect to fares, meals and accommodation.</p><p><strong>43.2</strong> Exception Subject to subclause 43.1, this clause 43 does not apply where an Employee voluntarily chooses for personal reasons to stay in the location prior to or after the day on which the Employee is required to work by the Employer.</p>',7)])])}const y=o(n,[["render",l]]);export{d as __pageData,y as default};
